+        let rec = self.records.get(&link_ref)?;
+        if rec.task_a == task {
+            Some(rec.policy_a)
+        } else if rec.task_b == task {
+            Some(rec.policy_b)
+        } else {
+            None
+        }
+    }
+
+    /// Updates the exit policy for a task on the given link.
